1	// trust-origin 신뢰 원점 부트스트랩 선언 CLI.
2	// declare: 선행 10조건 검사 후 trust-origin record를 생성한다. WORKSTATE·applier-log는 수정하지 않는다.
3	// --self-test: $TEMP 사본에서 5개 case를 in-process로 검증한다.
4	using System.Diagnostics;
5	using System.Security.Cryptography;
6	using System.Text;
7	using System.Text.Encodings.Web;
8	using System.Text.Json;
9	using System.Text.Json.Nodes;
10	
11	internal static class TrustOriginCli
12	{
13	    // record 고정 경로 — 이 밖 경로에는 절대 쓰지 않는다.
14	    private const string RecordRelPath = "docs/handoff/trust-origin/TO-2026-001.json";
15	
16	    private static readonly JsonSerializerOptions WriteOptions = new()
17	    {
18	        WriteIndented = true,
19	        Encoder = JavaScriptEncoder.UnsafeRelaxedJsonEscaping,
20	    };
21	
22	    // knownException 항목 데이터 레코드.
23	    private record KnownException(string Code, string Subject, string What, string Why, string WhyNotReplayed);
24	
25	    // 자기 시험 전용 precondition 주입 레코드 — CLI·환경변수로 켤 수 없음.
26	    internal record PreconOverride(
27	        bool BuildVerified, bool FilesTracked, bool NoDirectMod,
28	        string CommitHash, bool AutoLauncherOff, bool HighRiskClosed);
29	
30	    // 자기 시험 seam — in-process 훅만. production 진입점에서 설정 불가.
31	    internal static bool NonInteractiveOverride;
32	    internal static PreconOverride? TestPrecon;
33	
34	    // trust-origin 진입점.
35	    internal static int Run(string[] args)
36	    {
37	        var sub = args.Length > 1 ? args[1] : "";
38	        if (string.Equals(sub, "declare", StringComparison.OrdinalIgnoreCase))
39	            return RunDeclare(args);
40	        if (string.Equals(sub, "--self-test", StringComparison.OrdinalIgnoreCase))
41	            return RunSelfTest();
42	        Console.Error.WriteLine(
43	            "{\"error\":\"trust-origin usage: declare --ack BOOTSTRAP_TRUST_ORIGIN [--known-exceptions-file <path>] | --self-test\"}");
44	        return 2;
45	    }
46	
47	    // declare: 비대화형 거부(약한 안전장치), ack 확인, precondition 검사, record 생성.
48	    private static int RunDeclare(string[] args)
49	    {
50	        // 약한 안전장치(신원 증명 아님) — 비대화형 실행 기본 거부.
51	        // 프로그램은 사람과 AI를 구분 못 한다(HUMAN_DECLARED_NOT_CRYPTOGRAPHICALLY_VERIFIED).
52	        if (!NonInteractiveOverride && (Console.IsInputRedirected || !Environment.UserInteractive))
53	        {
54	            Console.Error.WriteLine(
55	                "{\"error\":\"비대화형 실행 기본 거부\",\"code\":\"non-interactive-rejected\","
56	                + "\"note\":\"HUMAN_DECLARED_NOT_CRYPTOGRAPHICALLY_VERIFIED — 프로그램은 사람과 AI를 구분하지 못합니다\"}");
57	            return 1;
58	        }
59	        var map = ParseFlagMap(args, 2);
60	        if (!map.TryGetValue("ack", out var ackVal) ||
61	            !string.Equals(ackVal, "BOOTSTRAP_TRUST_ORIGIN", StringComparison.OrdinalIgnoreCase))
62	        {
63	            Console.Error.WriteLine("{\"error\":\"--ack BOOTSTRAP_TRUST_ORIGIN 필요\",\"code\":\"ack-missing\"}");
64	            return 1;
65	        }
66	        string root;
67	        try { root = GitTools.FindRepoRoot(); }
68	        catch (Exception ex) { WriteError($"repo root 탐색 실패: {ex.Message}"); return 2; }
69	
70	        List<KnownException> knownExceptions = [];
71	        if (map.TryGetValue("known-exceptions-file", out var efile))
72	        {
73	            try { knownExceptions = ParseKnownExceptions(JsonNode.Parse(File.ReadAllText(efile, new UTF8Encoding(false)))); }
74	            catch (Exception ex) { WriteError($"known-exceptions-file 읽기 실패: {ex.Message}"); return 2; }
75	        }
76	        return RunDeclareCore(root, knownExceptions);
77	    }
78	
79	    // declare 핵심 — root를 명시적으로 받아 자기 시험과 production 경로를 공유한다.
80	    private static int RunDeclareCore(string root, List<KnownException> knownExceptions)
81	    {
82	        var recordPath = Path.GetFullPath(
83	            Path.Combine(root, RecordRelPath.Replace('/', Path.DirectorySeparatorChar)));
84	        var wsPath = Path.Combine(root, "docs", "handoff", "WORKSTATE.json");
85	        var logPath = Path.Combine(root, "docs", "handoff", "WORKSTATE.applier-log.jsonl");
86	        var precon = TestPrecon;
87	
88	        // 기존 epoch 확인: trustEpoch >= 1 이면 거부.
89	        var epochExit = CheckEpochGuard(recordPath);
90	        if (epochExit.HasValue) return epochExit.Value;
91	
92	        // WORKSTATE 읽기.
93	        if (!File.Exists(wsPath)) { WriteError("WORKSTATE.json not found"); return 2; }
94	        string wsContent;
95	        try { wsContent = File.ReadAllText(wsPath, new UTF8Encoding(false)); }
96	        catch (Exception ex) { WriteError($"WORKSTATE.json 읽기 실패: {ex.Message}"); return 2; }
97	
98	        // 선행조건 2: reconciliation 실행 + 부분집합 검사.
99	        var (reconResult, reconExit) = RunReconciliationCheck(wsPath, logPath, knownExceptions);
100	        if (reconExit.HasValue) return reconExit.Value;
101	
102	        // 선행조건 1·3·4·9·10 검사.
103	        var preconExit = CheckAllPreconditions(root, precon);
104	        if (preconExit.HasValue) return preconExit.Value;
105	
106	        // 선행조건 5: WORKSTATE hash / 선행조건 6: applier-log hash.
107	        var workstateSha256 = ComputeSha256(wsContent);
108	        var logContent = File.Exists(logPath) ? File.ReadAllText(logPath, new UTF8Encoding(false)) : "";
109	        var applierLogSha256 = ComputeSha256(logContent);
110	
111	        // 선행조건 7: baseline commit hash.
112	        var (baselineCommit, commitExit) = GetBaselineCommit(root, precon);
113	        if (commitExit.HasValue) return commitExit.Value;
114	
115	        // record 생성 — declarationCommit 없음(자기참조 방지). 이 경로 외에는 쓰지 않는다.
116	        return BuildAndWriteRecord(
117	            recordPath, baselineCommit!, workstateSha256, applierLogSha256, reconResult!, knownExceptions);
118	    }
119	
120	    // 기존 epoch 확인 — trustEpoch >= 1 이면 exit 1, 없으면 null.
121	    private static int? CheckEpochGuard(string recordPath)
122	    {
123	        if (!File.Exists(recordPath)) return null;
124	        try
125	        {
126	            var existing = JsonNode.Parse(File.ReadAllText(recordPath))?.AsObject();
127	            if ((existing?["trustEpoch"]?.GetValue<int>() ?? 0) >= 1)
128	            {
129	                WriteError("trustEpoch >= 1 이미 존재 — 재선언 거부. 새 trust origin은 VERIFIED_HUMAN_APPROVAL receipt 필요");
130	                return 1;
131	            }
132	        }
133	        catch { /* 파싱 불가 시 아래 CreateNew에서 처리 */ }
134	        return null;
135	    }
136	
137	    // reconciliation을 실행하고 failure ⊆ knownExceptions 부분집합 검사를 수행한다.
138	    private static (ReconciliationResult? result, int? exitCode) RunReconciliationCheck(
139	        string wsPath, string logPath, List<KnownException> knownExceptions)
140	    {
141	        ReconciliationResult reconResult;
142	        try { reconResult = HandoffIntegrityChecker.Run(new ReconciliationOptions(wsPath, logPath)); }
143	        catch (Exception ex) { WriteError($"reconciliation 실행 실패: {ex.Message}"); return (null, 2); }
144	
145	        // 하네스 오류 시 별도 중단 — subject가 없어 부분집합 검사를 우회할 수 있다.
146	        if (reconResult.HarnessErrors.Count > 0)
147	        {
148	            var errs = string.Join("; ", reconResult.HarnessErrors.Select(e => e.Code));
149	            WriteError($"reconciliation 하네스 오류 — 선행조건 2 검증 불가: {errs}");
150	            return (null, 2);
151	        }
152	
153	        // 부분집합 검사: failures ⊆ knownExceptions. 명시되지 않은 failure → 선언 거부.
154	        var failureSubjects = reconResult.Failures
155	            .Select(f => f.Subject).Where(s => !string.IsNullOrWhiteSpace(s))
156	            .ToHashSet(StringComparer.OrdinalIgnoreCase);
157	        var knownSubjects = knownExceptions.Select(e => e.Subject).ToHashSet(StringComparer.OrdinalIgnoreCase);
158	        var unlisted = failureSubjects.Except(knownSubjects).ToList();
159	        if (unlisted.Count > 0)
160	        {
161	            Console.Error.WriteLine(new JsonObject
162	            {
163	                ["error"] = "명시되지 않은 reconciliation failure — 선언 거부",
164	                ["code"] = "unlisted-reconciliation-failure",
165	                ["unlistedSubjects"] = new JsonArray(unlisted.Select(s => (JsonNode?)s).ToArray()),
166	            }.ToJsonString());
167	            return (null, 1);
168	        }
169	        return (reconResult, null);
170	    }
171	
172	    // 선행조건 1·3·4·9·10을 검사한다. 미충족 시 exit code 반환, 전부 충족 시 null.
173	    private static int? CheckAllPreconditions(string root, PreconOverride? precon)
174	    {
175	        if (precon is not null && !precon.BuildVerified)
176	            { WriteError("선행조건 1 미충족 — build exit 0 필요"); return 1; }
177	        var filesTracked = precon?.FilesTracked ?? CheckFilesTracked(root);
178	        if (!filesTracked)
179	            { WriteError("선행조건 3 미충족 — StateApplierCli.cs 또는 HandoffIntegrityChecker.cs가 git-tracked 상태가 아님"); return 1; }
180	        var noDirectMod = precon?.NoDirectMod ?? CheckNoDirectMod(root);
181	        if (!noDirectMod)
182	            { WriteError("선행조건 4 미충족 — WORKSTATE.json 또는 applier-log.jsonl가 working tree에서 직접 수정됨"); return 1; }
183	        var autoOff = precon?.AutoLauncherOff ?? true;
184	        if (!autoOff)
185	            { WriteError("선행조건 9 미충족 — 자동 launcher 비활성 확인 필요"); return 1; }
186	        var highRiskClosed = precon?.HighRiskClosed ?? true;
187	        if (!highRiskClosed)
188	            { WriteError("선행조건 10 미충족 — high-risk transition fail-closed 확인 필요"); return 1; }
189	        return null;
190	    }
191	
192	    // 선행조건 7: baseline commit hash를 반환한다. 시험은 TestPrecon, production은 git.
193	    private static (string? commit, int? exitCode) GetBaselineCommit(string root, PreconOverride? precon)
194	    {
195	        if (precon is not null) return (precon.CommitHash, null);
196	        try { return (RunGitOutput(root, "rev-parse HEAD").Trim(), null); }
197	        catch (Exception ex) { WriteError($"git rev-parse HEAD 실패: {ex.Message}"); return (null, 2); }
198	    }
199	
200	    // record를 구성하고 고정 경로에 atomic-create로 쓴다.
201	    private static int BuildAndWriteRecord(
202	        string recordPath, string baselineCommit, string workstateSha256, string applierLogSha256,
203	        ReconciliationResult reconResult, List<KnownException> knownExceptions)
204	    {
205	        var reconVerdict = reconResult.Failures.Count == 0
206	            ? "VERIFIED_PASS" : "VERIFIED_PASS_WITH_KNOWN_EXCEPTIONS";
207	        // declarationCommit 필드 미포함 — 자기참조 방지. annotated tag로 연결.
208	        var record = new JsonObject
209	        {
210	            ["schemaVersion"] = 1, ["trustOriginId"] = "TO-2026-001", ["trustEpoch"] = 1,
211	            ["declarationType"] = "BOOTSTRAP_TRUST_ORIGIN", ["baselineCommit"] = baselineCommit,
212	            ["workstateSha256"] = workstateSha256, ["applierLogSha256"] = applierLogSha256,
213	            ["stateApplierSchemaVersion"] = 2, ["reconciliationSchemaVersion"] = 2,
214	            ["legacyHistory"] = "NOT_EXACTLY_REPLAY_VERIFIED",
215	            ["buildVerdict"] = "VERIFIED_PASS", ["reconciliationVerdict"] = reconVerdict,
216	            ["knownExceptions"] = BuildExceptionsArray(knownExceptions),
217	            ["normalTransitionReady"] = true, ["verifiedHumanApprovalReady"] = false,
218	            ["recoveryApplyReady"] = false, ["automatedExecutionReady"] = false,
219	            ["declaredBy"] = new JsonObject
220	            {
221	                ["actorType"] = "human", ["actorId"] = "bootstrap-operator",
222	                ["actorPath"] = "local-manual",
223	            },
224	            ["declarationStatus"] = "HUMAN_DECLARED_NOT_CRYPTOGRAPHICALLY_VERIFIED",
225	            ["declaredAt"] = DateTime.UtcNow.ToString("o"),
226	        };
227	        Directory.CreateDirectory(Path.GetDirectoryName(recordPath)!);
228	        try
229	        {
230	            using var fs = new FileStream(recordPath, FileMode.CreateNew, FileAccess.Write, FileShare.None);
231	            fs.Write(Encoding.UTF8.GetBytes(record.ToJsonString(WriteOptions)));
232	        }
233	        catch (IOException ex) { WriteError($"record atomic-create 실패 — 이미 존재하거나 쓰기 불가: {ex.Message}"); return 1; }
234	
235	        Console.WriteLine(new JsonObject
236	        {
237	            ["ok"] = true, ["trustOriginId"] = "TO-2026-001", ["trustEpoch"] = 1,
238	            ["baselineCommit"] = baselineCommit, ["workstateSha256"] = workstateSha256,
239	            ["applierLogSha256"] = applierLogSha256, ["recordPath"] = recordPath,
240	            ["reconciliationVerdict"] = reconVerdict,
241	            ["note"] = "선언 완료. 다음: git commit -m '[trust-origin] bootstrap TO-2026-001' → git tag trust-origin/TO-2026-001 <commitHash>",
242	        }.ToJsonString(WriteOptions));
243	        return 0;
244	    }
245	
246	    // --self-test: $TEMP 사본에서 5개 case를 in-process로 검증한다.
247	    private static int RunSelfTest()
248	    {
249	        var tmpBase = Path.Combine(Path.GetTempPath(), $"to-selftest-{Guid.NewGuid():N}");
250	        try { return RunSelfTestInDir(tmpBase); }
251	        finally
252	        {
253	            try { if (Directory.Exists(tmpBase)) Directory.Delete(tmpBase, recursive: true); } catch { }
254	            NonInteractiveOverride = false;
255	            TestPrecon = null;
256	        }
257	    }
258	
259	    // 임시 디렉토리에서 5개 case를 순서대로 실행하고 결과를 보고한다.
260	    private static int RunSelfTestInDir(string tmpRoot)
261	    {
262	        var wsDir = Path.Combine(tmpRoot, "docs", "handoff");
263	        var trustDir = Path.Combine(tmpRoot, "docs", "handoff", "trust-origin");
264	        Directory.CreateDirectory(wsDir);
265	        Directory.CreateDirectory(trustDir);
266	        Directory.CreateDirectory(Path.Combine(tmpRoot, ".git")); // FindRepoRoot 기준점
267	        var wsPath = Path.Combine(wsDir, "WORKSTATE.json");
268	        var logPath = Path.Combine(wsDir, "WORKSTATE.applier-log.jsonl");
269	        var recordPath = Path.Combine(trustDir, "TO-2026-001.json");
270	
271	        // knownExceptions에 명시된 오염 — LISTED-TRANSITION이 state에 있고 log에 없음 (declare-ok용)
272	        const string WsDirty = "{\"schemaVersion\":1,\"diId\":\"DI-00-04\",\"status\":\"in_progress\","
273	            + "\"blockers\":[],\"nextActions\":[\"test\"],\"phaseId\":\"P00\",\"wpId\":\"WP-00\","
274	            + "\"updatedAt\":\"2026-07-14\",\"updatedBy\":\"self-test\","
275	            + "\"appliedTransitions\":[{\"id\":\"LISTED-TRANSITION\",\"appliedAt\":\"2026-07-14T00:00:00Z\"}]}";
276	        // 깨끗한 WORKSTATE — appliedTransitions 없음 → reconciliation PASS
277	        const string WsClean = "{\"schemaVersion\":1,\"diId\":\"DI-00-04\",\"status\":\"in_progress\","
278	            + "\"blockers\":[],\"nextActions\":[\"test\"],\"phaseId\":\"P00\",\"wpId\":\"WP-00\","
279	            + "\"updatedAt\":\"2026-07-14\",\"updatedBy\":\"self-test\",\"appliedTransitions\":[]}";
280	        // 미명시 오염 — UNLISTED-TRANSITION이 state·log·knownExceptions 어디에도 없음 (unlisted-failure용)
281	        const string WsUnlisted = "{\"schemaVersion\":1,\"diId\":\"DI-00-04\",\"status\":\"in_progress\","
282	            + "\"blockers\":[],\"nextActions\":[\"test\"],\"phaseId\":\"P00\",\"wpId\":\"WP-00\","
283	            + "\"updatedAt\":\"2026-07-14\",\"updatedBy\":\"self-test\","
284	            + "\"appliedTransitions\":[{\"id\":\"UNLISTED-TRANSITION\",\"appliedAt\":\"2026-07-14T00:00:00Z\"}]}";
285	
286	        var goodPrecon = new PreconOverride(true, true, true, "abc123def456abc123def456abc123def456abc1", true, true);
287	        var mismatches = new JsonArray();
288	        var caseResults = new JsonArray();
289	        // 실행 순서: declare-ok → no-self-reference(declare-ok 결과 재사용) → unlisted-failure → redeclare → record-path-fixed
290	        RunCaseDeclareOk(tmpRoot, wsPath, logPath, recordPath, WsDirty, goodPrecon, caseResults, mismatches);
291	        RunCaseNoSelfReference(recordPath, caseResults, mismatches);
292	        RunCaseUnlistedFailure(tmpRoot, wsPath, logPath, recordPath, WsUnlisted, goodPrecon, caseResults, mismatches);
293	        RunCaseRedeclare(tmpRoot, wsPath, logPath, recordPath, WsClean, goodPrecon, caseResults, mismatches);
294	        RunCaseRecordPathFixed(tmpRoot, wsPath, logPath, recordPath, WsClean, goodPrecon, caseResults, mismatches);
295	        NonInteractiveOverride = false; TestPrecon = null;
296	        if (mismatches.Count == 0)
297	        {
298	            Console.WriteLine(new JsonObject { ["selfTest"] = "trust-origin", ["verdict"] = "PASS",
299	                ["casesRun"] = caseResults.Count, ["cases"] = caseResults,
300	                ["selfFalsificationNote"] = "기대값을 틀리게 적으면 mismatches > 0 → exit 1. 판정선 4: 기대 epoch를 2로 바꿔 FAIL 실증.",
301	            }.ToJsonString(WriteOptions));
302	            return 0;
303	        }
304	        Console.Error.WriteLine(new JsonObject { ["selfTest"] = "trust-origin", ["verdict"] = "FAIL",
305	            ["mismatchCount"] = mismatches.Count, ["mismatches"] = mismatches, ["cases"] = caseResults,
306	        }.ToJsonString(WriteOptions));
307	        return 1;
308	    }
309	
310	    // case: declare-ok — failure가 knownExceptions에 명시돼 있으면 record 생성, trustEpoch=1.
311	    private static void RunCaseDeclareOk(
312	        string tmpRoot, string wsPath, string logPath, string recordPath,
313	        string wsDirty, PreconOverride precon, JsonArray caseResults, JsonArray mismatches)
314	    {
315	        ResetFixture(wsPath, wsDirty, logPath, recordPath);
316	        NonInteractiveOverride = true; TestPrecon = precon;
317	        var exceptions = new List<KnownException>
318	        {
319	            new("state-transition-not-logged", "LISTED-TRANSITION",
320	                "자기 시험용 fixture — state에 있지만 log에 없는 전이", "self-test fixture", "self-test only"),
321	        };
322	        var exit = RunDeclareCore(tmpRoot, exceptions);
323	        var recExists = File.Exists(recordPath);
324	        var epoch = 0; string? commit = null; var hasDC = false; string? verdict = null;
325	        if (recExists)
326	        {
327	            var rec = JsonNode.Parse(File.ReadAllText(recordPath))?.AsObject();
328	            epoch = rec?["trustEpoch"]?.GetValue<int>() ?? 0;
329	            commit = rec?["baselineCommit"]?.GetValue<string>();
330	            hasDC = rec?.ContainsKey("declarationCommit") ?? false;
331	            verdict = rec?["reconciliationVerdict"]?.GetValue<string>();
332	        }
333	        var ok = exit == 0 && recExists && epoch == 1 && commit == precon.CommitHash
334	            && !hasDC && verdict == "VERIFIED_PASS_WITH_KNOWN_EXCEPTIONS";
335	        caseResults.Add(new JsonObject { ["case"] = "declare-ok", ["exit"] = exit, ["recordExists"] = recExists,
336	            ["trustEpoch"] = epoch, ["commitMatch"] = (commit == precon.CommitHash),
337	            ["noDeclarationCommit"] = !hasDC, ["reconciliationVerdict"] = verdict, ["pass"] = ok });
338	        if (!ok) mismatches.Add(new JsonObject { ["case"] = "declare-ok",
339	            ["expected"] = "exit=0, record, epoch=1, commitMatch, no-DC, verdict=VERIFIED_PASS_WITH_KNOWN_EXCEPTIONS",
340	            ["actual"] = $"exit={exit},exists={recExists},epoch={epoch},commit={commit},hasDC={hasDC},verdict={verdict}" });
341	    }
342	
343	    // case: no-self-reference — declare-ok가 생성한 record에 declarationCommit 필드가 없다.
344	    private static void RunCaseNoSelfReference(string recordPath, JsonArray caseResults, JsonArray mismatches)
345	    {
346	        var recExists = File.Exists(recordPath);
347	        var hasDC = false;
348	        if (recExists)
349	        {
350	            try { var rec = JsonNode.Parse(File.ReadAllText(recordPath))?.AsObject(); hasDC = rec?.ContainsKey("declarationCommit") ?? false; }
351	            catch { hasDC = true; }
352	        }
353	        var ok = recExists && !hasDC;
354	        caseResults.Add(new JsonObject { ["case"] = "no-self-reference", ["recordExists"] = recExists, ["hasDeclarationCommit"] = hasDC, ["pass"] = ok });
355	        if (!ok) mismatches.Add(new JsonObject { ["case"] = "no-self-reference",
356	            ["expected"] = "record exists, declarationCommit 없음", ["actual"] = $"recExists={recExists},hasDC={hasDC}" });
357	    }
358	
359	    // case: unlisted-failure — reconciliation failure가 knownExceptions에 없으면 선언 거부.
360	    private static void RunCaseUnlistedFailure(
361	        string tmpRoot, string wsPath, string logPath, string recordPath,
362	        string wsUnlisted, PreconOverride precon, JsonArray caseResults, JsonArray mismatches)
363	    {
364	        ResetFixture(wsPath, wsUnlisted, logPath, recordPath);
365	        NonInteractiveOverride = true; TestPrecon = precon;
366	        var exit = RunDeclareCore(tmpRoot, []); // knownExceptions 비어 있음 → UNLISTED-TRANSITION 미명시 → 거부
367	        var recCreated = File.Exists(recordPath);
368	        var ok = exit == 1 && !recCreated;
369	        caseResults.Add(new JsonObject { ["case"] = "unlisted-failure", ["exit"] = exit, ["recordCreated"] = recCreated, ["pass"] = ok });
370	        if (!ok) mismatches.Add(new JsonObject { ["case"] = "unlisted-failure",
371	            ["expected"] = "exit=1 (선언 거부), record 미생성", ["actual"] = $"exit={exit},recordCreated={recCreated}" });
372	    }
373	
374	    // case: redeclare — trustEpoch >= 1 이미 존재하면 거부.
375	    private static void RunCaseRedeclare(
376	        string tmpRoot, string wsPath, string logPath, string recordPath,
377	        string wsClean, PreconOverride precon, JsonArray caseResults, JsonArray mismatches)
378	    {
379	        ResetFixture(wsPath, wsClean, logPath, recordPath);
380	        Directory.CreateDirectory(Path.GetDirectoryName(recordPath)!);
381	        File.WriteAllText(recordPath, "{\"schemaVersion\":1,\"trustOriginId\":\"TO-2026-001\",\"trustEpoch\":1}", new UTF8Encoding(false));
382	        NonInteractiveOverride = true; TestPrecon = precon;
383	        var exit = RunDeclareCore(tmpRoot, []);
384	        var ok = exit == 1;
385	        caseResults.Add(new JsonObject { ["case"] = "redeclare", ["exit"] = exit, ["pass"] = ok });
386	        if (!ok) mismatches.Add(new JsonObject { ["case"] = "redeclare",
387	            ["expected"] = "exit=1 (재선언 거부)", ["actual"] = $"exit={exit}" });
388	    }
389	
390	    // case: record-path-fixed — 선언은 canonical record 경로 외 다른 파일을 쓰지 않는다.
391	    private static void RunCaseRecordPathFixed(
392	        string tmpRoot, string wsPath, string logPath, string recordPath,
393	        string wsClean, PreconOverride precon, JsonArray caseResults, JsonArray mismatches)
394	    {
395	        ResetFixture(wsPath, wsClean, logPath, recordPath);
396	        NonInteractiveOverride = true; TestPrecon = precon;
397	        var beforeFiles = Directory.GetFiles(tmpRoot, "*", SearchOption.AllDirectories)
398	            .Select(Path.GetFullPath).ToHashSet(StringComparer.OrdinalIgnoreCase);
399	        var exit = RunDeclareCore(tmpRoot, []);
400	        var afterFiles = Directory.GetFiles(tmpRoot, "*", SearchOption.AllDirectories)
401	            .Select(Path.GetFullPath).ToHashSet(StringComparer.OrdinalIgnoreCase);
402	        var newFiles = afterFiles.Except(beforeFiles).ToList();
403	        var canonicalPath = Path.GetFullPath(recordPath);
404	        var onlyCanonical = exit == 0 && newFiles.Count == 1 &&
405	            string.Equals(newFiles[0], canonicalPath, StringComparison.OrdinalIgnoreCase);
406	        caseResults.Add(new JsonObject { ["case"] = "record-path-fixed", ["exit"] = exit,
407	            ["newFileCount"] = newFiles.Count, ["onlyCanonicalPath"] = onlyCanonical, ["pass"] = onlyCanonical });
408	        if (!onlyCanonical) mismatches.Add(new JsonObject { ["case"] = "record-path-fixed",
409	            ["expected"] = "exit=0, 신규 파일 1개만 (canonical path)",
410	            ["actual"] = $"exit={exit},newFiles=[{string.Join(";", newFiles)}]" });
411	    }
412	
413	    // 자기 시험용 fixture 초기화 — WORKSTATE·log를 고정값으로, record를 삭제.
414	    private static void ResetFixture(string wsPath, string wsContent, string logPath, string recordPath)
415	    {
416	        File.WriteAllText(wsPath, wsContent, new UTF8Encoding(false));
417	        File.WriteAllText(logPath, "", new UTF8Encoding(false));
418	        if (File.Exists(recordPath)) File.Delete(recordPath);
419	    }
420	
421	    // knownExceptions JSON 배열을 파싱한다.
422	    private static List<KnownException> ParseKnownExceptions(JsonNode? node)
423	    {
424	        var list = new List<KnownException>();
425	        if (node is not JsonArray arr) return list;
426	        foreach (var item in arr.OfType<JsonObject>())
427	        {
428	            var subject = item["subject"]?.GetValue<string>() ?? "";
429	            if (string.IsNullOrWhiteSpace(subject)) continue;
430	            list.Add(new KnownException(
431	                Code: item["code"]?.GetValue<string>() ?? "", Subject: subject,
432	                What: item["what"]?.GetValue<string>() ?? "", Why: item["why"]?.GetValue<string>() ?? "",
433	                WhyNotReplayed: item["whyNotReplayed"]?.GetValue<string>() ?? ""));
434	        }
435	        return list;
436	    }
437	
438	    // knownExceptions 목록을 JsonArray로 변환한다.
439	    private static JsonArray BuildExceptionsArray(List<KnownException> exceptions)
440	    {
441	        var arr = new JsonArray();
442	        foreach (var e in exceptions)
443	            arr.Add(new JsonObject { ["code"] = e.Code, ["subject"] = e.Subject, ["what"] = e.What,
444	                ["why"] = e.Why, ["whyNotReplayed"] = e.WhyNotReplayed });
445	        return arr;
446	    }
447	
448	    // StateApplierCli·HandoffIntegrityChecker가 git-tracked 상태인지 확인한다.
449	    private static bool CheckFilesTracked(string root)
450	    {
451	        foreach (var rel in new[] { "server/StateApplierCli.cs", "server/Harness/HandoffIntegrityChecker.cs" })
452	            if (RunGitExitCode(root, $"ls-files --error-unmatch \"{rel}\"") != 0) return false;
453	        return true;
454	    }
455	
456	    // WORKSTATE·applier-log가 working tree에서 직접 수정되지 않았는지 확인한다.
457	    private static bool CheckNoDirectMod(string root)
458	    {
459	        var output = RunGitOutput(root,
460	            "status --porcelain -- docs/handoff/WORKSTATE.json docs/handoff/WORKSTATE.applier-log.jsonl");
461	        return string.IsNullOrWhiteSpace(output);
462	    }
463	
464	    // git 명령의 exit code를 반환한다.
465	    private static int RunGitExitCode(string root, string arguments)
466	    {
467	        using var p = new Process();
468	        p.StartInfo = new ProcessStartInfo("git", arguments)
469	        {
470	            WorkingDirectory = root, RedirectStandardOutput = true,
471	            RedirectStandardError = true, UseShellExecute = false,
472	        };
473	        p.Start(); p.StandardOutput.ReadToEnd(); p.StandardError.ReadToEnd(); p.WaitForExit();
474	        return p.ExitCode;
475	    }
476	
477	    // git 명령의 stdout을 반환한다.
478	    private static string RunGitOutput(string root, string arguments)
479	    {
480	        using var p = new Process();
481	        p.StartInfo = new ProcessStartInfo("git", arguments)
482	        {
483	            WorkingDirectory = root, RedirectStandardOutput = true,
484	            RedirectStandardError = true, UseShellExecute = false,
485	        };
486	        p.Start(); var output = p.StandardOutput.ReadToEnd(); p.WaitForExit();
487	        return output;
488	    }
489	
490	    // --key value 쌍을 파싱한다.
491	    private static Dictionary<string, string> ParseFlagMap(string[] args, int startIndex)
492	    {
493	        var map = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
494	        for (var i = startIndex; i < args.Length; i++)
495	            if (args[i].StartsWith("--", StringComparison.Ordinal) && i + 1 < args.Length)
496	            { map[args[i][2..]] = args[i + 1]; i++; }
497	        return map;
498	    }
499	
500	    // SHA-256을 소문자 hex로 계산한다.
501	    private static string ComputeSha256(string content)
502	        => Convert.ToHexString(SHA256.HashData(Encoding.UTF8.GetBytes(content))).ToLowerInvariant();
503	
504	    // stderr에 JSON 오류 메시지를 출력한다.
505	    private static void WriteError(string message)
506	        => Console.Error.WriteLine($"{{\"error\":\"{message}\"}}");
507	}
